/**
 * App.js — Proof of Precedence
 * Elite redesign: cinematic hero, mixed light/dark sections,
 * scroll-reveal animations, real photography, no MetaMask.
 */

import React, { useState, useCallback, useRef, useEffect } from "react";
import { ethers } from "ethers";
import "./App.css";

const REGISTRY_ABI = [
  "function submitPaper(string calldata _ipfsCID) external",
  "function getPaper(string calldata _ipfsCID) external view returns (string memory, address, uint256, bool)",
  "function paperExists(string calldata _ipfsCID) external view returns (bool)",
  "function totalPapers() external view returns (uint256)",
  "event PaperSubmitted(string indexed ipfsCID, address indexed author, uint256 timestamp)",
];

const CONTRACT_ADDRESS = process.env.REACT_APP_CONTRACT_ADDRESS || "";
const PINATA_API_KEY   = process.env.REACT_APP_PINATA_API_KEY   || "";
const PINATA_SECRET    = process.env.REACT_APP_PINATA_SECRET    || "";
const RPC_URL          = process.env.REACT_APP_RPC_URL          || "http://127.0.0.1:8545";
const DEFAULT_KEY      = process.env.REACT_APP_PRIVATE_KEY      || "";

function getSigner(pk) {
  return new ethers.Wallet(pk, new ethers.JsonRpcProvider(RPC_URL));
}

async function uploadToPinata(file, onMsg) {
  const fd = new FormData();
  fd.append("file", file, file.name);
  fd.append("pinataMetadata", JSON.stringify({ name: file.name }));
  fd.append("pinataOptions",  JSON.stringify({ cidVersion: 1 }));
  onMsg("Uploading to IPFS via Pinata…");
  const res = await fetch("https://api.pinata.cloud/pinning/pinFileToIPFS", {
    method: "POST",
    headers: { pinata_api_key: PINATA_API_KEY, pinata_secret_api_key: PINATA_SECRET },
    body: fd,
  });
  if (!res.ok) throw new Error(`Pinata error ${res.status}: ${await res.text()}`);
  return (await res.json()).IpfsHash;
}

// ── Scroll reveal hook ─────────────────────────────────────────
function useScrollReveal() {
  useEffect(() => {
    const els = document.querySelectorAll(".reveal");
    const io = new IntersectionObserver(
        (entries) => entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add("visible"); io.unobserve(e.target); } }),
        { threshold: 0.12 }
    );
    els.forEach(el => io.observe(el));
    return () => io.disconnect();
  }, []);
}

// ── CopyField ──────────────────────────────────────────────────
function CopyField({ label, value, panel }) {
  const [copied, setCopied] = useState(false);
  const copy = () => { navigator.clipboard.writeText(value); setCopied(true); setTimeout(() => setCopied(false), 1800); };
  return (
      <div className="result-row">
        <span className="result-row-label">{label}</span>
        <div className="result-row-val">
          <span style={{ flex: 1 }}>{value}</span>
          <button className="copy-btn" onClick={copy}>{copied ? "✓ Copied" : "Copy"}</button>
        </div>
      </div>
  );
}

// ── Status ─────────────────────────────────────────────────────
function Status({ type, msg }) {
  if (!msg) return null;
  return (
      <div className={`status status-${type}`}>
        {type === "loading" ? <span className="spin" /> : <span className="status-icon">{type === "success" ? "✓" : "✕"}</span>}
        <span>{msg}</span>
      </div>
  );
}

// ═══════════════════════════════════════════════════════════════
export default function App() {
  const [scrolled, setScrolled]   = useState(false);
  const [activeTab, setActiveTab] = useState("upload");
  const appRef = useRef(null);

  // Wallet
  const [privateKey, setPrivateKey]   = useState(DEFAULT_KEY);
  const [wallet, setWallet]           = useState("");
  const [wStatus, setWStatus]         = useState("idle");
  const [wError, setWError]           = useState("");

  // Upload
  const [file, setFile]               = useState(null);
  const [uploadCid, setUploadCid]     = useState("");
  const [upStatus, setUpStatus]       = useState("idle");
  const [upMsg, setUpMsg]             = useState("");
  const [manualCid, setManualCid]     = useState("");
  const fileRef = useRef(null);

  // Submit
  const [subCid, setSubCid]           = useState("");
  const [subAddr, setSubAddr]         = useState(CONTRACT_ADDRESS);
  const [subStatus, setSubStatus]     = useState("idle");
  const [subMsg, setSubMsg]           = useState("");
  const [txHash, setTxHash]           = useState("");
  const [subTs, setSubTs]             = useState(null);

  // Verify
  const [verCid, setVerCid]           = useState("");
  const [verAddr, setVerAddr]         = useState(CONTRACT_ADDRESS);
  const [verStatus, setVerStatus]     = useState("idle");
  const [verResult, setVerResult]     = useState(null);

  useScrollReveal();

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);

  const scrollToApp = () => appRef.current?.scrollIntoView({ behavior: "smooth" });
  const scrollToHow = () => document.querySelector(".how-section")?.scrollIntoView({ behavior: "smooth" });

  const connectWallet = useCallback(async () => {
    if (!privateKey.trim()) { setWError("Enter a private key."); setWStatus("error"); return; }
    setWStatus("loading"); setWError("");
    try {
      const addr = await getSigner(privateKey.trim()).getAddress();
      setWallet(addr); setWStatus("success");
    } catch { setWError("Invalid key or RPC unreachable."); setWStatus("error"); }
  }, [privateKey]);

  const handleDrop = (e) => {
    e.preventDefault();
    const f = e.dataTransfer.files[0];
    if (f) { setFile(f); setUploadCid(""); setUpMsg(""); setUpStatus("idle"); }
  };

  const handleFileSelect = (e) => {
    const f = e.target.files[0];
    if (f) { setFile(f); setUploadCid(""); setUpMsg(""); setUpStatus("idle"); }
  };

  const handleUpload = async () => {
    if (!PINATA_API_KEY || !file) {
      const cid = manualCid.trim();
      if (!cid) { setUpMsg("Paste a CID to continue."); setUpStatus("error"); return; }
      setUploadCid(cid); setSubCid(cid); setVerCid(cid);
      setUpStatus("success"); setUpMsg("CID accepted."); return;
    }
    setUpStatus("loading"); setUpMsg("");
    try {
      const cid = await uploadToPinata(file, setUpMsg);
      setUploadCid(cid); setSubCid(cid); setVerCid(cid);
      setUpStatus("success"); setUpMsg("Successfully pinned to IPFS.");
    } catch (err) { setUpStatus("error"); setUpMsg(err.message); }
  };

  const handleSubmit = async () => {
    if (!subCid.trim())  { setSubMsg("Enter a CID.");              setSubStatus("error"); return; }
    if (!subAddr.trim()) { setSubMsg("Enter contract address.");   setSubStatus("error"); return; }
    if (!wallet)         { setSubMsg("Connect wallet first.");     setSubStatus("error"); return; }
    setSubStatus("loading"); setSubMsg("Sending transaction…"); setTxHash("");
    try {
      const signer   = getSigner(privateKey.trim());
      const registry = new ethers.Contract(subAddr, REGISTRY_ABI, signer);
      if (await registry.paperExists(subCid)) {
        setSubStatus("error"); setSubMsg("Already registered. Verify it in the Verify tab."); return;
      }
      const tx = await registry.submitPaper(subCid);
      setTxHash(tx.hash); setSubMsg("Awaiting confirmation…");
      const receipt  = await tx.wait(1);
      const block    = await new ethers.JsonRpcProvider(RPC_URL).getBlock(receipt.blockNumber);
      setSubTs(block.timestamp);
      setVerCid(subCid); setVerAddr(subAddr);
      setSubStatus("success"); setSubMsg(`Confirmed in block #${receipt.blockNumber}`);
    } catch (err) { setSubStatus("error"); setSubMsg(err?.reason || err?.message || "Failed."); }
  };

  const handleVerify = async () => {
    if (!verCid.trim())  { setVerResult({ error: "Enter a CID." });              setVerStatus("error"); return; }
    if (!verAddr.trim()) { setVerResult({ error: "Enter contract address." });   setVerStatus("error"); return; }
    setVerStatus("loading"); setVerResult(null);
    try {
      const registry = new ethers.Contract(verAddr, REGISTRY_ABI, new ethers.JsonRpcProvider(RPC_URL));
      const [cid, author, timestamp, exists] = await registry.getPaper(verCid);
      const total = await registry.totalPapers();
      if (!exists) { setVerStatus("error"); setVerResult({ exists: false }); }
      else { setVerStatus("success"); setVerResult({ exists: true, cid, author, timestamp: Number(timestamp), total: total.toString() }); }
    } catch (err) { setVerStatus("error"); setVerResult({ error: err.message }); }
  };

  const hasPinata = Boolean(PINATA_API_KEY && PINATA_SECRET);

  return (
      <div className="app">

        {/* ══ NAVBAR ══ */}
        <nav className={`navbar ${scrolled ? "scrolled" : ""}`}>
          <div className="nav-brand">
            <div className="nav-brand-mark">⛓</div>
            <span className="nav-brand-name">Proof of Precedence</span>
          </div>
          <div className="nav-links">
            <button className="nav-link" onClick={scrollToHow}>How It Works</button>
            <button className="nav-link" onClick={scrollToApp}>Launch App</button>
          </div>
          <div className="nav-cta">
            {wallet ? (
                <div className="nav-wallet-badge">
                  <div className="wallet-dot-live" />
                  {wallet.slice(0,6)}…{wallet.slice(-4)}
                </div>
            ) : (
                <button className="btn btn-outline-light btn-sm" onClick={scrollToApp}>Connect</button>
            )}
          </div>
        </nav>

        {/* ══ HERO ══ */}
        <section className="hero">
          <div className="hero-bg" />
          <div className="hero-overlay" />

          <div className="hero-content">
            <div className="hero-tag">
              <div className="hero-tag-dot" />
              Blockchain · IPFS · Immutable Records
            </div>

            <h1 className="hero-h1">Establish Your</h1>
            <h1 className="hero-h1-sub"><em>Research Priority.</em></h1>

            <p className="hero-desc">
              The first decentralised system for academic authorship verification.
              Your work, timestamped forever on the blockchain — unchallengeable,
              publicly verifiable, and owned by no one but you.
            </p>

            <div className="hero-actions">
              <button className="btn-hero-main" onClick={scrollToApp}>
                <span>Register a Paper</span>
              </button>
              <button className="btn-hero-ghost" onClick={scrollToHow}>
                How It Works
              </button>
            </div>
          </div>

          <div className="hero-stats">
            {[
              { val: "SHA-256", label: "Content Hashing" },
              { val: "EVM",     label: "Smart Contract Layer" },
              { val: "IPFS",    label: "Decentralised Storage" },
            ].map(({ val, label }) => (
                <div className="hero-stat" key={label}>
                  <div className="hero-stat-val">{val}</div>
                  <div className="hero-stat-label">{label}</div>
                </div>
            ))}
          </div>

          <div className="hero-scroll-hint">
            <div className="hero-scroll-line" />
            <span className="hero-scroll-text">Scroll</span>
          </div>
        </section>

        {/* ══ MANIFESTO — LIGHT ══ */}
        <section className="manifesto">
          <div className="manifesto-inner">
            <div>
              <div className="manifesto-label reveal">The Problem</div>
              <h2 className="manifesto-side-title reveal">Why this exists.</h2>
            </div>
            <div className="manifesto-body">
              <p className="manifesto-para reveal">
                Academic priority disputes are as old as science itself. When two researchers
                independently arrive at the same discovery, the community needs an{" "}
                <strong>objective, tamper-proof record</strong> of who arrived first.
              </p>
              <p className="manifesto-para reveal">
                Today's systems — journal timestamps, arXiv submissions, institutional
                repositories — all depend on <strong>centralised servers</strong> whose
                records can be altered and whose operators must be blindly trusted.
              </p>
              <p className="manifesto-para reveal">
                Proof of Precedence changes this. By combining <strong>IPFS content
                addressing</strong> with an <strong>Ethereum smart contract</strong>, we create
                a permanent, public, and mathematically verifiable record that requires
                no trust in any single institution.
              </p>
            </div>
          </div>
        </section>

        {/* ══ HOW IT WORKS — DARK WITH IMAGES ══ */}
        <section className="how-section">
          {[
            {
              num: "01",
              tag: "Step One",
              title: "Upload to IPFS",
              desc: "Your PDF is uploaded to the InterPlanetary File System via Pinata. IPFS calculates a Content Identifier — the SHA-256 hash of your file's exact bytes. Any modification, however small, produces a completely different CID.",
              details: ["Content-addressed storage", "Pinata pinning ensures availability", "CID is your document's fingerprint"],
              img: "https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=900&q=80",
            },
            {
              num: "02",
              tag: "Step Two",
              title: "Register On-Chain",
              desc: "Your CID, wallet address, and a network-consensus timestamp are written into a Solidity smart contract deployed on the Polygon network. The contract permanently rejects any future attempt to register the same CID.",
              details: ["Immutable blockchain record", "Cryptographic author identity", "Network-verified timestamp"],
              img: "https://images.unsplash.com/photo-1639322537228-f710d846310a?w=900&q=80",
            },
            {
              num: "03",
              tag: "Step Three",
              title: "Verify Anywhere",
              desc: "Anyone in the world can query the contract with a CID. The blockchain returns the author address, the timestamp, and the full precedence record — instantly, permanently, and without requiring any trusted third party.",
              details: ["Public and permissionless", "No intermediary needed", "Verifiable in milliseconds"],
              img: "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=900&q=80",
            },
          ].map(({ num, tag, title, desc, details, img }) => (
              <div className="how-step reveal" key={num}>
                <div className="how-step-image">
                  <img src={img} alt={title} loading="lazy" />
                  <div className="how-step-image-overlay" />
                  <div className="how-step-num-overlay">{num}</div>
                </div>
                <div className="how-step-content">
                  <div className="how-step-tag">{tag} — {num}</div>
                  <h3 className="how-step-title">{title}</h3>
                  <p className="how-step-desc">{desc}</p>
                  <div className="how-step-detail">
                    {details.map(d => (
                        <div className="how-step-detail-item" key={d}>
                          <div className="how-detail-bullet" />
                          <span>{d}</span>
                        </div>
                    ))}
                  </div>
                </div>
              </div>
          ))}
        </section>

        {/* ══ APP SECTION — LIGHT ══ */}
        <section className="app-section" ref={appRef}>
          <div className="app-section-inner">
            <div className="section-eyebrow reveal">The Application</div>
            <h2 className="section-h2 reveal">Register or verify a paper.</h2>

            {/* Wallet strip */}
            <div className="wallet-strip reveal">
              <div>
                <div className="wallet-strip-label">Wallet Connection</div>
                {wallet ? (
                    <div className="wallet-strip-addr">
                      <div className="wallet-dot-live" />
                      {wallet}
                      <span style={{ fontSize: "0.7rem", color: "var(--text-light3)", marginLeft: 4 }}>· Hardhat Local</span>
                    </div>
                ) : (
                    <span style={{ fontSize: "0.82rem", color: "var(--text-light3)" }}>Enter your private key to sign transactions</span>
                )}
              </div>
              {!wallet && (
                  <div className="wallet-key-row">
                    <input
                        className="field-input"
                        type="password"
                        placeholder="Private key (0x…)"
                        value={privateKey}
                        onChange={e => setPrivateKey(e.target.value)}
                        style={{ flex: 1 }}
                    />
                    <button className="btn btn-gold btn-sm" onClick={connectWallet} disabled={wStatus === "loading"}>
                      {wStatus === "loading" ? <><span className="spin" /> Connecting</> : <span>Connect</span>}
                    </button>
                  </div>
              )}
              {wError && <Status type="error" msg={wError} />}
            </div>

            {/* Tabs */}
            <div className="reveal">
              <div className="tab-bar">
                {[
                  { id: "upload", icon: "⬆", label: "Upload to IPFS",    badge: "01" },
                  { id: "submit", icon: "⛓", label: "Submit to Chain",   badge: "02" },
                  { id: "verify", icon: "✓", label: "Verify Precedence", badge: "03" },
                ].map(({ id, icon, label, badge }) => (
                    <button key={id} className={`tab-btn ${activeTab === id ? "active" : ""}`} onClick={() => setActiveTab(id)}>
                      <span className="tab-icon">{icon}</span>
                      {label}
                      <span className="tab-badge">{badge}</span>
                    </button>
                ))}
              </div>

              <div className="tab-panels">

                {/* ── Upload tab — dark ── */}
                <div className={`tab-panel ${activeTab === "upload" ? "active" : ""}`}>
                  <div className="panel-upload">
                    <div className="panel-title">Upload Your Paper to IPFS</div>
                    <div className="panel-desc">Your PDF is pinned on IPFS. Its cryptographic fingerprint is returned for blockchain registration.</div>

                    {hasPinata ? (
                        <>
                          <div
                              className={`drop-zone ${file ? "has-file" : ""}`}
                              onDrop={handleDrop}
                              onDragOver={e => e.preventDefault()}
                              onClick={() => fileRef.current?.click()}
                          >
                            <input ref={fileRef} type="file" accept=".pdf" style={{ display: "none" }} onChange={handleFileSelect} />
                            {file ? (
                                <div className="file-preview-row">
                                  <span className="file-preview-icon">📄</span>
                                  <div>
                                    <div className="file-name">{file.name}</div>
                                    <div className="file-size">{(file.size / 1024).toFixed(1)} KB</div>
                                  </div>
                                </div>
                            ) : (
                                <>
                                  <div className="drop-icon-box">⬆</div>
                                  <div className="drop-main">Drop your PDF here</div>
                                  <div className="drop-sub">or click to browse files — PDF only</div>
                                </>
                            )}
                          </div>
                          <button className="btn btn-gold w-full" onClick={handleUpload} disabled={upStatus === "loading" || !file}>
                            {upStatus === "loading" ? <><span className="spin" /><span>Uploading…</span></> : <span>Upload to IPFS via Pinata</span>}
                          </button>
                        </>
                    ) : (
                        <div className="manual-block">
                          <div className="manual-note">
                            <span>ℹ</span>
                            <span>No Pinata keys configured. Upload your PDF at <a href="https://app.pinata.cloud" target="_blank" rel="noreferrer">app.pinata.cloud</a>, then paste the CID below.</span>
                          </div>
                          <div className="field-group">
                            <label className="field-label">IPFS CID</label>
                            <input className="field-input" placeholder="bafybei…" value={manualCid} onChange={e => setManualCid(e.target.value)} />
                          </div>
                          <button className="btn btn-gold w-full" onClick={handleUpload} style={{ marginTop: 8 }}><span>Use This CID</span></button>
                        </div>
                    )}

                    <Status type={upStatus} msg={upMsg} />

                    {uploadCid && (
                        <div className="result-box">
                          <div className="result-box-header">IPFS Result</div>
                          <div className="result-box-body">
                            <CopyField label="CID" value={uploadCid} panel="upload" />
                          </div>
                          <div style={{ padding: "16px 20px", display: "flex", gap: 12 }}>
                            <a className="btn btn-outline-light btn-sm" href={`https://gateway.pinata.cloud/ipfs/${uploadCid}`} target="_blank" rel="noreferrer" style={{ textDecoration: "none" }}>
                              View on IPFS ↗
                            </a>
                            <button className="btn btn-gold btn-sm" onClick={() => { setSubCid(uploadCid); setActiveTab("submit"); }}>
                              <span>Continue to Submit →</span>
                            </button>
                          </div>
                        </div>
                    )}
                  </div>
                </div>

                {/* ── Submit tab — dark navy ── */}
                <div className={`tab-panel ${activeTab === "submit" ? "active" : ""}`}>
                  <div className="panel-submit">
                    <div className="panel-title">Submit CID to Blockchain</div>
                    <div className="panel-desc">Your wallet signs a transaction permanently recording the CID, your address, and a network timestamp on-chain.</div>

                    <div className="field-group">
                      <label className="field-label">Contract Address</label>
                      <input className="field-input" placeholder="0x…" value={subAddr} onChange={e => setSubAddr(e.target.value)} />
                    </div>
                    <div className="field-group">
                      <label className="field-label">IPFS CID</label>
                      <input className="field-input" placeholder="bafybei…" value={subCid} onChange={e => setSubCid(e.target.value)} />
                    </div>

                    <button className="btn btn-gold w-full" onClick={handleSubmit} disabled={subStatus === "loading"} style={{ marginTop: 8 }}>
                      {subStatus === "loading" ? <><span className="spin" /><span>Submitting…</span></> : <span>Submit to Blockchain</span>}
                    </button>

                    <Status type={subStatus} msg={subMsg} />

                    {subStatus === "success" && txHash && (
                        <div className="cert cert-confirmed">
                          <div className="cert-header">
                            <div className="cert-seal">🔒</div>
                            <div>
                              <div className="cert-title">Precedence Established</div>
                              <div className="cert-subtitle">This document is permanently registered. No earlier on-chain record exists for this CID.</div>
                            </div>
                          </div>
                          <div className="cert-body">
                            <div className="cert-grid">
                              <div className="cert-item">
                                <div className="cert-item-label">Transaction Hash</div>
                                <div className="cert-item-val">{txHash.slice(0,22)}…</div>
                              </div>
                              {subTs && (
                                  <div className="cert-item">
                                    <div className="cert-item-label">Block Timestamp</div>
                                    <div className="cert-item-val">{new Date(subTs * 1000).toUTCString()}</div>
                                  </div>
                              )}
                              <div className="cert-item">
                                <div className="cert-item-label">IPFS CID</div>
                                <div className="cert-item-val">{subCid.slice(0,26)}…</div>
                              </div>
                              <div className="cert-item">
                                <div className="cert-item-label">Author Wallet</div>
                                <div className="cert-item-val">{wallet.slice(0,22)}…</div>
                              </div>
                            </div>
                          </div>
                          <div className="cert-footer">
                            <button className="btn btn-outline-light btn-sm" onClick={() => { setVerCid(subCid); setActiveTab("verify"); }}>
                              Verify This Paper →
                            </button>
                          </div>
                        </div>
                    )}
                  </div>
                </div>

                {/* ── Verify tab — light ── */}
                <div className={`tab-panel ${activeTab === "verify" ? "active" : ""}`}>
                  <div className="panel-verify">
                    <div className="panel-title">Verify Proof of Precedence</div>
                    <div className="panel-desc">Query the blockchain with any CID to retrieve the author, timestamp, and precedence status. No wallet required — this is a public read.</div>

                    <div className="field-group">
                      <label className="field-label">Contract Address</label>
                      <input className="field-input" placeholder="0x…" value={verAddr} onChange={e => setVerAddr(e.target.value)} />
                    </div>
                    <div className="field-group">
                      <label className="field-label">IPFS CID to Verify</label>
                      <input className="field-input" placeholder="bafybei…" value={verCid} onChange={e => setVerCid(e.target.value)} />
                    </div>

                    <button className="btn btn-teal w-full" onClick={handleVerify} disabled={verStatus === "loading"} style={{ marginTop: 8 }}>
                      {verStatus === "loading" ? <><span className="spin" /><span>Querying Blockchain…</span></> : "Verify on Blockchain"}
                    </button>

                    {verResult?.error && <Status type="error" msg={verResult.error} />}

                    {verResult?.exists === false && (
                        <div className="cert cert-denied" style={{ marginTop: 20 }}>
                          <div className="cert-header">
                            <div className="cert-seal">✕</div>
                            <div>
                              <div className="cert-title">Not Registered</div>
                              <div className="cert-subtitle">This CID has no on-chain record in this registry.</div>
                            </div>
                          </div>
                        </div>
                    )}

                    {verResult?.exists === true && (
                        <div className="cert cert-confirmed" style={{ marginTop: 20 }}>
                          <div className="cert-header">
                            <div className="cert-seal">✅</div>
                            <div>
                              <div className="cert-title">Proof of Precedence Confirmed</div>
                              <div className="cert-subtitle">This record is immutable. The author and timestamp have been verified on-chain.</div>
                            </div>
                          </div>
                          <div className="cert-body">
                            <div className="cert-grid">
                              <div className="cert-item">
                                <div className="cert-item-label">Author Wallet</div>
                                <div className="cert-item-val">{verResult.author}</div>
                              </div>
                              <div className="cert-item">
                                <div className="cert-item-label">Registered At</div>
                                <div className="cert-item-val">{new Date(verResult.timestamp * 1000).toUTCString()}</div>
                              </div>
                              <div className="cert-item">
                                <div className="cert-item-label">IPFS CID</div>
                                <div className="cert-item-val">{verResult.cid}</div>
                              </div>
                              <div className="cert-item">
                                <div className="cert-item-label">Total Papers in Registry</div>
                                <div className="cert-item-val">{verResult.total}</div>
                              </div>
                            </div>
                          </div>
                        </div>
                    )}
                  </div>
                </div>

              </div>
            </div>
          </div>
        </section>

        {/* ══ TRUST SECTION — DARK ══ */}
        <section className="trust-section">
          <div className="trust-inner">
            <div className="section-eyebrow reveal" style={{ color: "var(--gold2)" }}>Why Trust It</div>
            <h2 className="section-h2 reveal" style={{ color: "var(--text-light)" }}>
              Built on mathematical certainty.
            </h2>
            <div className="trust-grid">
              {[
                { icon: "🔐", title: "Tamper-Proof",   desc: "Once written to the blockchain, no record can be altered. Not by us, not by anyone." },
                { icon: "🌐", title: "Public",          desc: "Every record is openly queryable by anyone in the world with the contract address and CID." },
                { icon: "⏱",  title: "Timestamped",    desc: "Block timestamps are set by network consensus — impossible to backdate or manipulate." },
                { icon: "🔑", title: "Self-Sovereign",  desc: "You own your record. No account, no login, no intermediary — just your wallet and the chain." },
              ].map(({ icon, title, desc }) => (
                  <div className="trust-item reveal" key={title}>
                    <span className="trust-icon">{icon}</span>
                    <div className="trust-item-title">{title}</div>
                    <div className="trust-item-desc">{desc}</div>
                  </div>
              ))}
            </div>
          </div>
        </section>

        {/* ══ FOOTER ══ */}
        <footer className="footer">
          <div className="footer-inner">
            <div>
              <div className="footer-brand-name">Proof of Precedence</div>
              <div className="footer-brand-desc">
                A decentralised system for immutable academic authorship verification,
                built on Ethereum-compatible smart contracts and IPFS.
